// Nodo: "Calculate Currency Strength"
const allItems = $input.all();

console.log(`📊 Recibidos ${allItems.length} items`);

// Inicializar variables
let eurData = {};
let gbpData = {};
let usdData = {};
let jpyData = {};
let chfData = {};

// Extraer datos de cada item
for (const item of allItems) {
    const data = item.json;

    // Detectar cuál moneda es por el contenido
    if (data.eur && data.eur.usd !== undefined) {
        eurData = data.eur;
        console.log("✅ Datos EUR cargados");
    }
    if (data.gbp && data.gbp.usd !== undefined) {
        gbpData = data.gbp;
        console.log("✅ Datos GBP cargados");
    }
    if (data.usd && data.usd.eur !== undefined) {
        usdData = data.usd;
        console.log("✅ Datos USD cargados");
    }
    if (data.jpy && data.jpy.usd !== undefined) {
        jpyData = data.jpy;
        console.log("✅ Datos JPY cargados");
    }
    if (data.chf && data.chf.usd !== undefined) {
        chfData = data.chf;
        console.log("✅ Datos CHF cargados");
    }
}

// Calcular tasas
const eurUsd = eurData.usd || 0;
const gbpUsd = gbpData.usd || 0;
const usdJpy = 1 / (jpyData.usd || 1);
const usdChf = 1 / (chfData.usd || 1);

// Calcular fortaleza de cada moneda
const eurStrength = eurUsd > 1.09 ? "bullish" : (eurUsd < 1.07 ? "bearish" : "neutral");
const gbpStrength = gbpUsd > 1.27 ? "bullish" : (gbpUsd < 1.25 ? "bearish" : "neutral");
const usdStrength = (eurUsd < 1.08 && gbpUsd < 1.26) ? "bullish" : 
                    (eurUsd > 1.10 && gbpUsd > 1.28) ? "bearish" : "neutral";
const jpyStrength = usdJpy < 148 ? "bullish" : (usdJpy > 152 ? "bearish" : "neutral");
const chfStrength = usdChf < 0.89 ? "bullish" : (usdChf > 0.91 ? "bearish" : "neutral");

// Calcular puntuación de sentimiento
let sentimentScore = 0;
if (eurStrength === "bullish") sentimentScore += 25;
if (eurStrength === "bearish") sentimentScore -= 25;
if (gbpStrength === "bullish") sentimentScore += 25;
if (gbpStrength === "bearish") sentimentScore -= 25;
if (usdStrength === "bullish") sentimentScore += 25;
if (usdStrength === "bearish") sentimentScore -= 25;
if (jpyStrength === "bullish") sentimentScore += 15;
if (jpyStrength === "bearish") sentimentScore -= 15;
if (chfStrength === "bullish") sentimentScore += 10;
if (chfStrength === "bearish") sentimentScore -= 10;

sentimentScore = Math.min(100, Math.max(-100, sentimentScore));

let overallSentiment = "neutral";
if (sentimentScore > 30) overallSentiment = "bullish";
if (sentimentScore < -30) overallSentiment = "bearish";

console.log(`📊 ÍNDICE DE FORTALEZA:`);
console.log(`   EUR: ${eurStrength} (EUR/USD: ${eurUsd})`);
console.log(`   GBP: ${gbpStrength} (GBP/USD: ${gbpUsd})`);
console.log(`   USD: ${usdStrength}`);
console.log(`   JPY: ${jpyStrength} (USD/JPY: ${usdJpy.toFixed(2)})`);
console.log(`   CHF: ${chfStrength} (USD/CHF: ${usdChf.toFixed(4)})`);
console.log(`   Sentimiento: ${overallSentiment} (${sentimentScore})`);

return [{
    json: {
        timestamp: new Date().toISOString(),
        rates: {
            EURUSD: eurUsd,
            GBPUSD: gbpUsd,
            USDJPY: usdJpy,
            USDCHF: usdChf
        },
        strength: {
            EUR: eurStrength,
            GBP: gbpStrength,
            USD: usdStrength,
            JPY: jpyStrength,
            CHF: chfStrength
        },
        sentiment: {
            score: sentimentScore,
            overall: overallSentiment,
            market_mood: sentimentScore > 50 ? "greedy" : (sentimentScore < -50 ? "fearful" : "calm")
        }
    }
}];
